import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import "./App.css";

import Home from './pages/home/Home';
import Services from './pages/services/Services';
import Blogs from './pages/blogs/Blogs';
import About from './pages/about/About';
import Contactus from './pages/contactus/ContactUs';
import Quiz from './pages/quiz/Quiz';
import Booking from './pages/services/booking/Booking';
import BlogDetail from './pages/blogs/BlogDetail'; // Fixed path
import ThankYouMessage from './pages/thankmessage/ThankMessage';
import CookiesPolicy from './pages/policies/CookiesPolicy';
import PrivacyPolicy from './pages/policies/PrivacyPolicy';
import LegalNotice from './pages/policies/LegalNotice';

import Layout from './components/Layout';
import Payment from './pages/services/booking/payment/Payment';

const API_BASE_URL = 'https://e-nutritionist-9bb9c8f7b2bc.herokuapp.com/'; 
const API_Local_Host = "http://localhost:3000"

const App = () => {
  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<Home localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/services" element={<Services localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/payment" element={<Payment localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/blogs" element={<Blogs localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/blogs/:slug" element={<BlogDetail localHost={API_Local_Host} heroku={API_BASE_URL}/>} /> {/* Updated route */}
          <Route path="/about" element={<About localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/contactus" element={<Contactus localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/quiz" element={<Quiz localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/booking" element={<Booking localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/thankyoumessage" element={<ThankYouMessage localHost={API_Local_Host} heroku={API_BASE_URL}/>} />
          <Route path="/cookiespolicy" element={<CookiesPolicy />} />
          <Route path="/privacypolicy" element={<PrivacyPolicy />} />
          <Route path="/legalnotice" element={<LegalNotice />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;
